#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void unionSet(int* parent, int* rank, int x, int y) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
    }
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int* bestFriend = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &bestFriend[i]);
        bestFriend[i]--;
    }
    int* parent = (int*)malloc(N * sizeof(int));
    int* rank = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        parent[i] = i;
        rank[i] = 0;
    }
    for (int i = 0; i < N; i++) {
        unionSet(parent, rank, i, bestFriend[i]);
    }
    for (int i = 0; i < Q; i++) {
        int L, R;
        scanf("%d %d", &L, &R);
        L--;
        R--;
        int* tempParent = (int*)malloc(N * sizeof(int));
        int* tempRank = (int*)malloc(N * sizeof(int));
        for (int j = 0; j < N; j++) {
            tempParent[j] = parent[j];
            tempRank[j] = rank[j];
        }
        for (int j = 0; j < N; j++) {
            if (j < L || j > R) {
                tempParent[j] = j;
                tempRank[j] = 0;
            }
        }
        for (int j = L; j <= R; j++) {
            if (bestFriend[j] < L || bestFriend[j] > R) {
                tempParent[j] = j;
                tempRank[j] = 0;
            } else {
                unionSet(tempParent, tempRank, j, bestFriend[j]);
            }
        }
        int count = 0;
        for (int j = L; j <= R; j++) {
            if (tempParent[j] == j) {
                count++;
            }
        }
        printf("%d\n", count);
        free(tempParent);
        free(tempRank);
    }
    free(bestFriend);
    free(parent);
    free(rank);
    return 0;
}

