        int[] rank = new int[N];
        for (int i = 0; i < N; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            unionSet(parent, rank, i, bestFriend[i]);
        }
        for (int i = 0; i < Q; i++) {
            int L = scanner.nextInt() - 1;
            int R = scanner.nextInt() - 1;
            int[] tempParent = parent.clone();
            int[] tempRank = rank.clone();
            for (int j = 0; j < N; j++) {
                if (j < L || j > R) {
                    tempParent[j] = j;
                    tempRank[j] = 0;
                }
