                    unionSet(tempParent, tempRank, j, bestFriend[j]);
                }
            }
            int count = 0;
            for (int j = L; j <= R; j++) {
                if (tempParent[j] == j) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

